package com.iotmanager.network;

import java.util.List;

public class IoTClientConfig {

    private String cloudApiBaseUrl;
    private String cloudApiHost;
    private String authToken;
    private String apiKey;
    private String clientVersion = "1.0.0";
    private boolean debug = false;
    private boolean trustLocalCertificates = true;
    private int maxRetries = 3;
    private long retryDelayMs = 1000;
    private List<String> cloudCertificatePins;

    private IoTClientConfig() {
    }

    public static Builder builder() {
        return new Builder();
    }

    public String getCloudApiBaseUrl() {
        return cloudApiBaseUrl;
    }

    public String getCloudApiHost() {
        return cloudApiHost;
    }

    public String getAuthToken() {
        return authToken;
    }

    public void setAuthToken(String authToken) {
        this.authToken = authToken;
    }

    public String getApiKey() {
        return apiKey;
    }

    public String getClientVersion() {
        return clientVersion;
    }

    public boolean isDebug() {
        return debug;
    }

    public boolean isTrustLocalCertificates() {
        return trustLocalCertificates;
    }

    public int getMaxRetries() {
        return maxRetries;
    }

    public long getRetryDelayMs() {
        return retryDelayMs;
    }

    public List<String> getCloudCertificatePins() {
        return cloudCertificatePins;
    }

    public static class Builder {
        private final IoTClientConfig config = new IoTClientConfig();

        public Builder cloudApiBaseUrl(String url) {
            config.cloudApiBaseUrl = url;
            return this;
        }

        public Builder cloudApiHost(String host) {
            config.cloudApiHost = host;
            return this;
        }

        public Builder authToken(String token) {
            config.authToken = token;
            return this;
        }

        public Builder apiKey(String apiKey) {
            config.apiKey = apiKey;
            return this;
        }

        public Builder clientVersion(String version) {
            config.clientVersion = version;
            return this;
        }

        public Builder debug(boolean debug) {
            config.debug = debug;
            return this;
        }

        public Builder trustLocalCertificates(boolean trust) {
            config.trustLocalCertificates = trust;
            return this;
        }

        public Builder maxRetries(int maxRetries) {
            config.maxRetries = maxRetries;
            return this;
        }

        public Builder retryDelayMs(long delayMs) {
            config.retryDelayMs = delayMs;
            return this;
        }

        public Builder cloudCertificatePins(List<String> pins) {
            config.cloudCertificatePins = pins;
            return this;
        }

        public IoTClientConfig build() {
            if (config.cloudApiBaseUrl == null) {
                throw new IllegalArgumentException("Cloud API base URL is required");
            }
            if (config.cloudApiHost == null) {
                // Extract host from URL
                config.cloudApiHost = config.cloudApiBaseUrl
                        .replaceFirst("https?://", "")
                        .split("[:/]")[0];
            }
            return config;
        }
    }
}

