package com.iotmanager.network;

public class IoTNetworkException extends Exception {

    private int statusCode;

    public IoTNetworkException(String message) {
        super(message);
    }

    public IoTNetworkException(String message, Throwable cause) {
        super(message, cause);
    }

    public IoTNetworkException(String message, int statusCode) {
        super(message);
        this.statusCode = statusCode;
    }

    public IoTNetworkException(String message, int statusCode, Throwable cause) {
        super(message, cause);
        this.statusCode = statusCode;
    }

    public int getStatusCode() {
        return statusCode;
    }
}

// ============================================================
// RetryPolicy.java - Retry configuration
// ============================================================
package com.iotmanager.network;

public class RetryPolicy {

    final int maxRetries;
    final long baseDelayMs;

    public RetryPolicy(int maxRetries, long baseDelayMs) {
        this.maxRetries = maxRetries;
        this.baseDelayMs = baseDelayMs;
    }

    public long getDelayForAttempt(int attempt) {
        // Exponential backoff with jitter
        long delay = (long) (baseDelayMs * Math.pow(2, attempt));
        long jitter = (long) (delay * 0.1 * Math.random());
        return delay + jitter;
    }

    public boolean shouldRetryOnCode(int statusCode) {
        return statusCode == 408 || statusCode == 429 || statusCode == 500
                || statusCode == 502 || statusCode == 503 || statusCode == 504;
    }
}

