// ============================================================
// DeviceScanner.java - Network device discovery
// ============================================================
package com.iotmanager.network;

import android.os.Handler;
import android.os.Looper;
import android.util.Log;

import com.iotmanager.network.models.DeviceInfo;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicBoolean;

public class DeviceScanner {

    private static final String TAG = "DeviceScanner";
    private final IoTHttpClient httpClient;
    private final ExecutorService scanExecutor;
    private final Handler mainHandler;
    private final AtomicBoolean isScanning = new AtomicBoolean(false);

    public interface ScanCallback {
        void onDeviceFound(DeviceInfo device);
        void onScanComplete(List<DeviceInfo> devices);
        void onScanError(String error);
    }

    public DeviceScanner(IoTHttpClient httpClient) {
        this.httpClient = httpClient;
        this.scanExecutor = Executors.newFixedThreadPool(20);
        this.mainHandler = new Handler(Looper.getMainLooper());
    }

    public void scanSubnet(String subnetPrefix, int port, boolean useHttps, ScanCallback callback) {
        if (isScanning.getAndSet(true)) {
            callback.onScanError("Scan already in progress");
            return;
        }

        new Thread(() -> {
            List<DeviceInfo> foundDevices = new ArrayList<>();
            CountDownLatch latch = new CountDownLatch(254);

            for (int i = 1; i <= 254; i++) {
                final String ip = subnetPrefix + "." + i;
                scanExecutor.submit(() -> {
                    try {
                        String scheme = useHttps ? "https" : "http";
                        String url = scheme + "://" + ip + ":" + port + "/device/info";
                        IoTResponse<DeviceInfo> response = httpClient.getSync(url, DeviceInfo.class);

                        if (response.isSuccessful() && response.getData() != null) {
                            DeviceInfo device = response.getData();
                            device.setIpAddress(ip);
                            device.setPort(port);
                            device.setSupportsHttps(useHttps);

                            synchronized (foundDevices) {
                                foundDevices.add(device);
                            }

                            mainHandler.post(() -> callback.onDeviceFound(device));
                        }
                    } catch (IoTNetworkException e) {
                        // Device not found at this IP - expected
                    } finally {
                        latch.countDown();
                    }
                });
            }

            try {
                latch.await(60, TimeUnit.SECONDS);
            } catch (InterruptedException e) {
                Log.e(TAG, "Scan interrupted", e);
            }

            isScanning.set(false);
            mainHandler.post(() -> callback.onScanComplete(foundDevices));
        }).start();
    }

    public void stopScan() {
        isScanning.set(false);
    }

    public boolean isScanning() {
        return isScanning.get();
    }

    public void shutdown() {
        scanExecutor.shutdownNow();
    }
}

// ============================================================
// Usage Example - ExampleActivity.java
// ============================================================
package com.iotmanager;

import android.os.Bundle;
import android.util.Log;

import androidx.appcompat.app.AppCompatActivity;

import com.iotmanager.network.DeviceScanner;
import com.iotmanager.network.IoTClientConfig;
import com.iotmanager.network.IoTHttpClient;
import com.iotmanager.network.IoTNetworkException;
import com.iotmanager.network.IoTResponse;
import com.iotmanager.network.IoTResponseCallback;
import com.iotmanager.network.models.DeviceCommand;
import com.iotmanager.network.models.DeviceInfo;
import com.iotmanager.network.models.DeviceStatus;

import java.util.Arrays;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class ExampleActivity extends AppCompatActivity {

    private static final String TAG = "ExampleActivity";
    private IoTHttpClient httpClient;
    private DeviceScanner deviceScanner;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        // Initialize the HTTP client with configuration
        IoTClientConfig config = IoTClientConfig.builder()
                .cloudApiBaseUrl("https://api.myiotcloud.com")
                .cloudApiHost("api.myiotcloud.com")
                .apiKey("your-api-key-here")
                .authToken("your-auth-token")
                .clientVersion("1.0.0")
                .debug(true)
                .trustLocalCertificates(true)
                .maxRetries(3)
                .retryDelayMs(1000)
                .cloudCertificatePins(Arrays.asList(
                        "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA="
                ))
                .build();

        httpClient = IoTHttpClient.getInstance(config);
        deviceScanner = new DeviceScanner(httpClient);

        // Example: Scan local network for devices
        scanLocalNetwork();

        // Example: Talk to a known local device over HTTP (legacy)
        getDeviceStatusHttp("192.168.1.100", 8080);

        // Example: Talk to a known local device over HTTPS
        getDeviceStatusHttps("192.168.1.101", 8443);

        // Example: Send command to device
        sendCommand("192.168.1.100", 8080, false);

        // Example: Cloud API call
        fetchCloudDevices();
    }

    private void scanLocalNetwork() {
        deviceScanner.scanSubnet("192.168.1", 8080, false, new DeviceScanner.ScanCallback() {
            @Override
            public void onDeviceFound(DeviceInfo device) {
                Log.d(TAG, "Found device: " + device.getName() + " at " + device.getIpAddress());
            }

            @Override
            public void onScanComplete(List<DeviceInfo> devices) {
                Log.d(TAG, "Scan complete. Found " + devices.size() + " devices.");
            }

            @Override
            public void onScanError(String error) {
                Log.e(TAG, "Scan error: " + error);
            }
        });
    }

    private void getDeviceStatusHttp(String ip, int port) {
        // HTTP for legacy devices
        httpClient.getDeviceStatus(ip, port, false, DeviceStatus.class, new IoTResponseCallback<DeviceStatus>() {
            @Override
            public void onSuccess(IoTResponse<DeviceStatus> response) {
                DeviceStatus status = response.getData();
                Log.d(TAG, "Device online: " + status.isOnline() + ", temp: " + status.getTemperature());
            }

            @Override
            public void onError(IoTNetworkException exception) {
                Log.e(TAG, "Failed to get device status via HTTP", exception);
            }
        });
    }

    private void getDeviceStatusHttps(String ip, int port) {
        // HTTPS for newer devices
        httpClient.getDeviceStatus(ip, port, true, DeviceStatus.class, new IoTResponseCallback<DeviceStatus>() {
            @Override
            public void onSuccess(IoTResponse<DeviceStatus> response) {
                DeviceStatus status = response.getData();
                Log.d(TAG, "Device (HTTPS) online: " + status.isOnline());
            }

            @Override
            public void onError(IoTNetworkException exception) {
                Log.e(TAG, "Failed to get device status via HTTPS", exception);
            }
        });
    }

    private void sendCommand(String ip, int port, boolean useHttps) {
        Map<String, Object> params = new HashMap<>();
        params.put("brightness", 75);
        params.put("color", "#FF5500");

        DeviceCommand command = new DeviceCommand("set_light", params);

        httpClient.sendDeviceCommandAsync(ip, port, useHttps, command, String.class, new IoTResponseCallback<String>() {
            @Override
            public void onSuccess(IoTResponse<String> response) {
                Log.d(TAG, "Command sent successfully: " + response.getRawBody());
            }

            @Override
            public void onError(IoTNetworkException exception) {
                Log.e(TAG, "Failed to send command", exception);
            }
        });
    }

    private void fetchCloudDevices() {
        httpClient.getCloudDeviceList(DeviceInfo[].class, new IoTResponseCallback<DeviceInfo[]>() {
            @Override
            public void onSuccess(IoTResponse<DeviceInfo[]> response) {
                DeviceInfo[] devices = response.getData();
                if (devices != null) {
                    Log.d(TAG, "Cloud has " + devices.length + " registered devices");
                }
            }

            @Override
            public void onError(IoTNetworkException exception) {
                Log.e(TAG, "Failed to fetch cloud devices", exception);
            }
        });
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (deviceScanner != null) {
            deviceScanner.shutdown();
        }
        if (httpClient != null) {
            httpClient.cancelAll();
        }
    }
}